from dataclasses import dataclass

@dataclass
class EvalCase:
    input: str
    expected: str
    tags: list[str] = None

dataset = [
    EvalCase("Capital of France?", "Paris", ["easy"]),
    EvalCase("Capital of Myanmar?", "Naypyidaw", ["hard"]),
]

def exact_match(output: str, expected: str) -> float:
    return 1.0 if output.strip().lower() == expected.strip().lower() else 0.0
